    // Validate query parameters
    const { limit, offset, sortBy } = req.query;

    // Validate limit parameter
    if (limit && (!Number.isInteger(Number(limit)) || Number(limit) < 1 || Number(limit) > 100)) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be between 1 and 100.' 
      });
    }

    // Validate offset parameter
    if (offset && (!Number.isInteger(Number(offset)) || Number(offset) < 0)) {
      return res.status(400).json({ 
        error: 'Invalid offset parameter. Must be non-negative integer.' 
      });
    }

    // Validate sortBy parameter (whitelist allowed fields)
    const allowedFields = ['id', 'name', 'email'];
    if (sortBy && !allowedFields.includes(sortBy)) {
      return res.status(400).json({ 
        error: `Invalid sortBy parameter. Allowed: ${allowedFields.join(', ')}` 
      });
    }

    // Mock user data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ 
      error: 'Failed to fetch users. Please try again later.' 
    });
  }
});

